form:Form.form:Scripts:
		function remove_id(control, id)
{
var arr = Ctrl("arr_"+control).GetXValue();
arr = arr.split(',');          

var result ="";
var sep = ""
for(var t=0; t<arr.length; t++) if (arr[t] && arr[t] != id) { result += sep + arr[t]; sep=","; }

Ctrl("arr_"+control).SetXValue(result);
}

function add_ids(control, ids)
{
if (ids)
{
//Antiguos
var old = Ctrl("arr_"+control).GetXValue();
var current = { };
if (old)
{
old = old.split(',');          
for(var t=0; t<old.length; t++) current[old[t]] = true;
}

//Nuevos	
ids = ids.split(',');
var result = Ctrl("arr_"+control).GetXValue();
var sep = result ? "," : "";
for(var t=0; t<ids.length; t++) if (current[ids[t]]?false:true) { result += sep + ids[t]; sep=","; }

//Resultado
Ctrl("arr_"+control).SetXValue(result);
}
}


function ONLOAD()
{              
habilitarConfidenciales();
ONLOAD_MODULO();      
ONLOAD_CUSTOM();

refresh_ALL();
}

function clear(control)
{                                       
Ctrl("lst_"+control).SetXValue("");
Ctrl("arr_"+control).SetXValue("");
refresh(control);
}

function deleteItem(control)
{                                       
var sel = Ctrl("lst_"+control).GetXValue();
if (sel)
{
remove_id(control, sel);
Ctrl("lst_"+control).SetXValue("");
refresh(control);
}
} 

function refresh(control)
{                                       
var modo = Ctrl("modo_"+control).GetXValue();
var sel = Ctrl("lst_"+control).GetXValue();
var arr = Ctrl("arr_"+control).GetXValue();
var emp = Ctrl("empresa").GetXValue();

CtrlEnabled("lst_"+control+"_Add"   , emp && modo ? true : false);    
CtrlEnabled("lst_"+control+"_Delete", emp && modo && sel ? true : false);
CtrlEnabled("lst_"+control+"_Clear" , emp && modo && arr ? true : false);

Ctrl("lbl_"+control).m_HTMLObject.innerHTML = Ctrl("lbl_"+control).m_HTMLObject.innerHTML.split(':')[0] + (arr ? ": " + (arr.split(',').length == 1 ? "1 elemento" : arr.split(',').length + " elementos") : "");

//Lista de IDS!!!
var controlObj = Ctrl("lst_"+control);
  var page=controlObj.Page;
  controlObj.IDs=arr ? arr.split(',') : [];
  controlObj.ResetSQL();
  controlObj.GotoPage(page);
}

function add(control, flow)
{                
openNewFlowWait(
flow, 
"OPEN-GUIA", 
"<DATA empresa=\"" + Ctrl("empresa").GetXValue() + "\" />",
{
processResult: function(xmlin) 
{
var result = new NomadXML(xmlin);

if (result.GetAttr("action")=="ACCEPT")
{
	add_ids(control, result.GetAttr("ids"));
	refresh(control);
}

}
}, 
"S"
);  
}                             

function addWhere(control, campo)
{
var modo = Ctrl("modo_"+control).GetXValue();
var arr = Ctrl("arr_"+control).GetXValue();
var retval = "";
if (modo && arr)
{              
if (arr.split(',').length == 1)
retval = campo + (modo=="I"?"=":"!=") + arr;
else
retval = campo + (modo=="I"?" in (":" not in (") + arr + ")";
}
return retval;
}

var addWhereCount=0;
function addWhere2(control, campo, tablaF, campoF, campoI)
{
var modo = Ctrl("modo_"+control).GetXValue();
var arr = Ctrl("arr_"+control).GetXValue();
var retval = "";
if (modo && arr)
{
if (arr.split(',').length == 1)
retval = campo + (modo=="I"?" in ": " not in ") + "( select F" + addWhereCount + "." + campoF + " FROM " +tablaF + " as F" + addWhereCount + " WHERE F" + addWhereCount + "." + campoI + "=" + arr + ")";
else
retval = campo + (modo=="I"?" in ": " not in ") + "( select F" + addWhereCount + "." + campoF + " FROM " +tablaF + " as F" + addWhereCount + " WHERE F" + addWhereCount + "." + campoI + " in (" + arr + ") )";
addWhereCount++;
}
return retval;
}


function habilitarConfidenciales()
{

  var	np = GetProxy();
var nSQL = np.SQLService(); 	
var qry = Ctrl("main").getResource("qry_confidenciales");	 


var result = nSQL.GetXML(qry, "<DATA oi_user='"+np.Etty()+"'/>");
    var confidencial = result.GetAttr("confidencial");

    if(confidencial == "noconf")
    {
    Ctrl('cb_confidenciales').SetXValue('NC');
    Ctrl('cb_confidenciales').SetEnabled(false);
    } 
}

