function GetWhere()
{
//Pongo en 0 el contador de Tablas externas
addWhereCount=0;

//Comienzo
var where = "";
var sep = "";  
var aux = "";

//Fijos
if (Ctrl("empresa") && Ctrl("empresa").GetXValue()) { where+=sep+"LEG.oi_empresa="+Ctrl("empresa").GetXValue(); sep=" AND "; }
if (Ctrl("activos") && Ctrl("activos").GetXValue()=="1") { where+=sep+"LEG.oi_indic_activo=1"; sep=" AND "; }
if (Ctrl("fecha_i_desde") && Ctrl("fecha_i_desde").GetXValue()) { where+=sep+"LEG.f_ingreso>=\\'"+Ctrl("fecha_i_desde").GetXValue()+"\\'"; sep=" AND "; }
if (Ctrl("fecha_i_hasta") && Ctrl("fecha_i_hasta").GetXValue()) { where+=sep+"LEG.f_ingreso<=\\'"+Ctrl("fecha_i_hasta").GetXValue()+"\\'"; sep=" AND "; }
if (Ctrl("fecha_e_desde") && Ctrl("fecha_e_desde").GetXValue()) { where+=sep+"LEG.f_egreso>=\\'"+Ctrl("fecha_e_desde").GetXValue()+"\\'"; sep=" AND "; }
if (Ctrl("fecha_e_hasta") && Ctrl("fecha_e_hasta").GetXValue()) { where+=sep+"LEG.f_egreso<=\\'"+Ctrl("fecha_e_hasta").GetXValue()+"\\'"; sep=" AND "; }
if (Ctrl("cb_confidenciales") && Ctrl("cb_confidenciales").GetXValue()) 
{                                                                     
if (Ctrl("cb_confidenciales").GetXValue() == "C")
{
where+=sep+"LEG.l_confidencial=1"; sep=" AND "; 
} else
{
where+=sep+"LEG.l_confidencial=0"; sep=" AND "; 
}
}

//Listas
aux = addWhere_convenio();      if (aux) { where+=sep+aux; sep=" AND "; }
aux = addWhere_categoria();     if (aux) { where+=sep+aux; sep=" AND "; }	
aux = addWhere_puesto();        if (aux) { where+=sep+aux; sep=" AND "; }
aux = addWhere_posicion();      if (aux) { where+=sep+aux; sep=" AND "; }	
aux = addWhere_departamento();  if (aux) { where+=sep+aux; sep=" AND "; }
aux = addWhere_sector();        if (aux) { where+=sep+aux; sep=" AND "; }	
aux = addWhere_grupo_ccosto();  if (aux) { where+=sep+aux; sep=" AND "; }
aux = addWhere_centro_costo();  if (aux) { where+=sep+aux; sep=" AND "; }	
aux = addWhere_tipo_personal(); if (aux) { where+=sep+aux; sep=" AND "; }
aux = addWhere_legajo();        if (aux) { where+=sep+aux; sep=" AND "; }	
aux = addWhere_contrato();      if (aux) { where+=sep+aux; sep=" AND "; }
aux = addWhere_forma_pago();    if (aux) { where+=sep+aux; sep=" AND "; }	
aux = addWhere_funcion();       if (aux) { where+=sep+aux; sep=" AND "; }	
aux = addWhere_sindicato();     if (aux) { where+=sep+aux; sep=" AND "; }	
aux = addWhere_ubicacion();     if (aux) { where+=sep+aux; sep=" AND "; }	
aux = addWhere_estructura();    if (aux) { where+=sep+aux; sep=" AND "; }	


//Especiales
aux = addWhere_MODULO(); if (aux) { where+=sep+aux; sep=" AND "; }
aux = addWhere_CUSTOM(); if (aux) { where+=sep+aux; sep=" AND "; }	

//Resultado	       
Ctrl("where").SetXValue(where);
return where;	
}



function Filtrar()
{              
var where = GetWhere();
var result = ACCEPT();
if (result)
alert(result);
else
Ctrl("main").DoEvent("ACCEPT");
}

