// en una pantalla particular
// 
function addWhere_CUSTOM() { return ""; }


//
// Operaciones adicionales y validaciones antes
// de ejecutar el ACCEPT en el SERVIDOR, 
// si retorna NULL, se ejecuta el codigo en el servidor
// si retorna un TEXTO, se muestra como mensaje de error.    
//
// Este es un ejemplo donde prueba el WHERE EN LA DB.
// 
//
// PD: Este metodo siempre tiene que ser reemplazado en el FORMULARIO FINAL!!!!
// La validacion del largo del WHERE es muy importante, recordar que el query final 
// tiene que tener menos de 4000 caracteres de largo o no sera compatible con ORACLE.
// 
function ACCEPT()
{                      
//Obtengo el WHERE
var WHERE = Ctrl("where").GetXValue();

//Valido el largo del QUERY, es muy importante.
if (WHERE.length > 3000)
return "El resultado es muy grande y no podra ser procesado por el motor de Base de datos.";

//PRUEBA DE QUERY - SOLO PARA DEBUG
  var	np = GetProxy();
var nSQL = np.SQLService(); 	
var qry = Ctrl("main").getResource("qry_debug");	       
var param = new NomadXML("PARAM");
param.SetAttr("where", WHERE);
var result = nSQL.GetXML(qry, param.ToString());

//Muestro el resultado
return "("+WHERE.length+" - " + Math.round(WHERE.length * 100.0 / 3000.0) + "%) Registros: " + result.GetAttr("TOT") + " - EXECUTE OK - "+result.ToString();
}
